    18→export function computeStats(
    19→  counts: number[],
    20→  lastDigit: number,
    21→  total: number
    22→): DigitStats {
    23→  if (total === 0) {
    24→    return {
    25→      counts,
    26→      total,
    27→      lastDigit,
    28→      percentages: Array(10).fill("0.0"),
    29→      topDigits: [0, 1, 2],
    30→      bottomDigits: [9, 8, 7],
    31→      evenPercent: 50,
    32→      oddPercent: 50,
    33→      overPercent: 50,
    34→      underPercent: 50,
    35→      signal: "AI Waiting For Signal...",
    36→      matchesProbability: 72,
    37→      differsProbability: 81,
    38→      aiConfidence: 89,
    39→    };
    40→  }
    41→
    42→  const percentages = counts.map((c) => ((c / total) * 100).toFixed(1));
    43→
    44→  const sorted = counts
    45→    .map((count, index) => ({ count, index }))
    46→    .sort((a, b) => b.count - a.count);
    47→
    48→  const topDigits = [sorted[0].index, sorted[1].index, sorted[2].index];
    49→  const bottomDigits = [sorted[9].index, sorted[8].index, sorted[7].index];
    50→
    51→  let even = 0;
    52→  let odd = 0;
    53→  counts.forEach((count, index) => {
    54→    if (index % 2 === 0) even += count;
    55→    else odd += count;
    56→  });
    57→  const evenPercent = parseFloat(((even / total) * 100).toFixed(1));
    58→  const oddPercent = parseFloat(((odd / total) * 100).toFixed(1));
    59→
    60→  const over = counts.slice(6).reduce((a, b) => a + b, 0);
    61→  const under = counts.slice(0, 6).reduce((a, b) => a + b, 0);
    62→  const overPercent = parseFloat(((over / total) * 100).toFixed(1));
    63→  const underPercent = parseFloat(((under / total) * 100).toFixed(1));
    64→
    65→  const signal =
    66→    evenPercent > oddPercent
    67→      ? "AI SIGNAL → EVEN MARKET STRONG"
    68→      : "AI SIGNAL → ODD MARKET STRONG";
    69→
    70→  const topPct = parseFloat(percentages[topDigits[0]]);
    71→  const matchesProbability = Math.min(95, Math.max(55, Math.round(topPct * 2.5 + 45)));
    72→  const differsProbability = Math.min(95, Math.max(60, Math.round((100 - topPct) * 0.5 + 65)));
    73→  const aiConfidence = Math.min(97, Math.max(70, Math.round((evenPercent + overPercent) / 2 + 30)));
    74→
    75→  return {
    76→    counts,
    77→    total,
    78→    lastDigit,
    79→    percentages,
    80→    topDigits,
    81→    bottomDigits,
    82→    evenPercent,
    83→    oddPercent,
    84→    overPercent,
    85→    underPercent,
    86→    signal,
    87→    matchesProbability,
    88→    differsProbability,
    89→    aiConfidence,
    90→  };
    91→}
