    11→
    12→type SignalStrength = "STRONG" | "MODERATE" | "WEAK" | "NONE";
    13→
    14→type MarketSignal = {
    15→  market: { symbol: string; label: string };
    16→  tickCount: number;
    17→  lastQuote: number;
    18→  evenEdge: number;
    19→  oddEdge: number;
    20→  bestOver: { barrier: number; edge: number };
    21→  bestUnder: { barrier: number; edge: number };
    22→  topDigit: number;
    23→  topPct: number;
    24→  coldDigit: number;
    25→  coldPct: number;
    26→  signalStrength: SignalStrength;
    27→  recommendation: string;
    28→  recommendationColor: string;
    29→};
    30→
    31→const BARRIERS = [1, 2, 3, 4, 5, 6, 7, 8];
    32→
    33→function computeOverEdge(barrier: number, counts: number[], total: number): number {
    34→  const isOver34 = barrier === 3 || barrier === 4;
    35→  if (isOver34) {
    36→    const lowCount = [0, 1, 2].reduce((s, d) => s + counts[d], 0);
    37→    const lowPct = (lowCount / total) * 100;
    38→    return 30 - lowPct; // positive = digits 0-2 are rare = over signal
    39→  }
    40→  const targetCount = counts.slice(barrier + 1).reduce((a, b) => a + b, 0);
    41→  const targetPct = (targetCount / total) * 100;
    42→  const expected = ((9 - barrier) / 10) * 100;
    43→  return expected - targetPct; // positive = digits above barrier underrepresented
    44→}
    45→
    46→function computeUnderEdge(barrier: number, counts: number[], total: number): number {
    47→  const isUnder56 = barrier === 5 || barrier === 6;
    48→  if (isUnder56) {
    49→    const lowCount = [0, 1, 2, 3].reduce((s, d) => s + counts[d], 0);
    50→    const lowPct = (lowCount / total) * 100;
    51→    return lowPct - 40; // positive = 0-3 dominate = trend down
    52→  }
    53→  const targetCount = counts.slice(0, barrier).reduce((a, b) => a + b, 0);
    54→  const targetPct = (targetCount / total) * 100;
    55→  const expected = (barrier / 10) * 100;
    56→  return expected - targetPct;
    57→}
    58→
    59→function scoreStrength(edge: number): SignalStrength {
    60→  if (edge >= 8) return "STRONG";
    61→  if (edge >= 4) return "MODERATE";
    62→  if (edge >= 1) return "WEAK";
    63→  return "NONE";
    64→}
