    66→export default function SmartSignals({ allMarkets, onSelectMarket }: Props) {
    67→  const { theme } = useTheme();
    68→
    69→  const signals: MarketSignal[] = useMemo(() => {
    70→    return MARKETS.map((market) => {
    71→      const ms = allMarkets[market.symbol];
    72→      const counts = ms?.counts ?? Array(10).fill(0);
    73→      const total = Math.max(ms?.tickCount ?? 0, 1);
    74→      const lastQuote = ms?.lastQuote ?? 0;
    75→      const tickCount = ms?.tickCount ?? 0;
    76→
    77→      const stats = computeStats(counts, ms?.lastDigit ?? 0, ms?.tickCount ?? 0);
    78→
    79→      const evenEdge = 50 - stats.evenPercent;
    80→      const oddEdge = 50 - stats.oddPercent;
    81→
    82→      let bestOver = { barrier: 5, edge: -99 };
    83→      let bestUnder = { barrier: 5, edge: -99 };
    84→      for (const b of BARRIERS) {
    85→        const oe = computeOverEdge(b, counts, total);
    86→        const ue = computeUnderEdge(b, counts, total);
    87→        if (oe > bestOver.edge) bestOver = { barrier: b, edge: oe };
    88→        if (ue > bestUnder.edge) bestUnder = { barrier: b, edge: ue };
    89→      }
