    93→      const coldDigit = stats.bottomDigits[0];
    94→      const coldPct = parseFloat(stats.percentages[coldDigit]);
    95→
    96→      const maxEdge = Math.max(bestOver.edge, bestUnder.edge, Math.abs(evenEdge), Math.abs(oddEdge));
    97→      const strength = tickCount < 20 ? "NONE" : scoreStrength(maxEdge);
    98→
    99→      let recommendation = "Collecting data...";
   100→      let recommendationColor = theme.textSub;
   101→
   102→      if (tickCount >= 20) {
   103→        if (bestOver.edge >= bestUnder.edge && bestOver.edge >= Math.abs(evenEdge)) {
   104→          recommendation = `OVER ${bestOver.barrier} (+${bestOver.edge.toFixed(1)}%)`;
   105→          recommendationColor = "#3b82f6";
   106→        } else if (bestUnder.edge >= Math.abs(evenEdge)) {
   107→          recommendation = `UNDER ${bestUnder.barrier} (+${bestUnder.edge.toFixed(1)}%)`;
   108→          recommendationColor = "#a855f7";
   109→        } else if (evenEdge > 0) {
