   128→        coldDigit,
   129→        coldPct,
   130→        signalStrength: strength,
   131→        recommendation,
   132→        recommendationColor,
   133→      };
   134→    }).sort((a, b) => {
   135→      const order = { STRONG: 0, MODERATE: 1, WEAK: 2, NONE: 3 };
   136→      return order[a.signalStrength] - order[b.signalStrength];
   137→    });
