   171→          </div>
   172→        </div>
   173→        <div style={{ display: "flex", gap: "16px", marginLeft: "auto", flexWrap: "wrap" }}>
   174→          <div style={{ textAlign: "center" }}>
   175→            <div style={{ fontSize: "28px", fontWeight: 700, color: "#22c55e" }}>{strongCount}</div>
