import { useTheme } from "../contexts/ThemeContext";
import type { DigitStats } from "../types";

type Props = {
  stats: DigitStats;
};

type SignalCard = {
  id: string;
  label: string;
  sublabel: string;
  description: string;
  active: boolean;
  strength: "VERY STRONG" | "STRONG" | "MODERATE" | "PRESENT" | "INACTIVE";
  matchCount: number;
  activeColor: string;
  activeGlow: string;
  activeBg: string;
  icon: string;
};

function strengthBar(strength: SignalCard["strength"]) {
  const bars = { "VERY STRONG": 4, STRONG: 3, MODERATE: 2, PRESENT: 1, INACTIVE: 0 };
  const colors = {
    "VERY STRONG": "#22c55e",
    STRONG: "#3b82f6",
    MODERATE: "#f59e0b",
    PRESENT: "#8b5cf6",
    INACTIVE: "#374151",
  };
  const n = bars[strength];
  const c = colors[strength];
  return (
    <div style={{ display: "flex", gap: "3px", marginTop: "6px" }}>
      {[0, 1, 2, 3].map((i) => (
        <div
          key={i}
          style={{
            width: "18px",
            height: "5px",
            borderRadius: "3px",
            background: i < n ? c : "rgba(255,255,255,0.1)",
            transition: "background 0.3s",
          }}
        />
      ))}
    </div>
  );
}

export default function TradingSignals({ stats }: Props) {
  const { theme } = useTheme();
  const top3 = stats.topDigits; // [highest, 2nd, 3rd]

  const isEven = (d: number) => d % 2 === 0;
  const isOdd = (d: number) => d % 2 !== 0;

  const evenCount = top3.filter(isEven).length;
  const oddCount = top3.filter(isOdd).length;

  const underSignals: SignalCard[] = [
    {
      id: "under6",
      label: "UNDER 6",
      sublabel: "Digits 0–5",
      description: "All top digits below 6",
      active: top3.every((d) => d < 6),
      strength: top3.every((d) => d < 6) ? "VERY STRONG" : "INACTIVE",
      matchCount: top3.filter((d) => d < 6).length,
      activeColor: "#22c55e",
      activeGlow: "0 0 20px rgba(34,197,94,0.4), 0 0 40px rgba(34,197,94,0.15)",
      activeBg: "rgba(34,197,94,0.12)",
      icon: "🎯",
    },
    {
      id: "under7",
      label: "UNDER 7",
      sublabel: "Digits 0–6",
      description: "All top digits below 7",
      active: top3.every((d) => d < 7),
      strength: top3.every((d) => d < 7) ? "STRONG" : "INACTIVE",
      matchCount: top3.filter((d) => d < 7).length,
      activeColor: "#3b82f6",
      activeGlow: "0 0 20px rgba(59,130,246,0.4), 0 0 40px rgba(59,130,246,0.15)",
      activeBg: "rgba(59,130,246,0.12)",
      icon: "📈",
    },
    {
      id: "under8",
      label: "UNDER 8",
      sublabel: "Digits 0–7",
      description: "All top digits below 8",
      active: top3.every((d) => d < 8),
      strength: top3.every((d) => d < 8) ? "MODERATE" : "INACTIVE",
      matchCount: top3.filter((d) => d < 8).length,
      activeColor: "#f59e0b",
      activeGlow: "0 0 16px rgba(245,158,11,0.35), 0 0 32px rgba(245,158,11,0.12)",
      activeBg: "rgba(245,158,11,0.10)",
      icon: "📊",
    },
    {
      id: "under9",
      label: "UNDER 9",
      sublabel: "Digits 0–8",
      description: "All top digits below 9",
      active: top3.every((d) => d < 9),
      strength: top3.every((d) => d < 9) ? "PRESENT" : "INACTIVE",
      matchCount: top3.filter((d) => d < 9).length,
      activeColor: "#8b5cf6",
      activeGlow: "0 0 14px rgba(139,92,246,0.3), 0 0 28px rgba(139,92,246,0.1)",
      activeBg: "rgba(139,92,246,0.09)",
      icon: "🔵",
    },
  ];

  const evenSignal: SignalCard = {
    id: "even",
    label: "TRADE EVEN",
    sublabel: "Digits 0,2,4,6,8",
    description: "All top 3 digits are EVEN",
    active: evenCount === 3,
    strength:
      evenCount === 3 ? "VERY STRONG" : evenCount === 2 ? "MODERATE" : "INACTIVE",
    matchCount: evenCount,
    activeColor: "#06b6d4",
    activeGlow: "0 0 20px rgba(6,182,212,0.4), 0 0 40px rgba(6,182,212,0.15)",
    activeBg: "rgba(6,182,212,0.12)",
    icon: "⚡",
  };

  const oddSignal: SignalCard = {
    id: "odd",
    label: "TRADE ODD",
    sublabel: "Digits 1,3,5,7,9",
    description: "All top 3 digits are ODD",
    active: oddCount === 3,
    strength:
      oddCount === 3 ? "VERY STRONG" : oddCount === 2 ? "MODERATE" : "INACTIVE",
    matchCount: oddCount,
    activeColor: "#f97316",
    activeGlow: "0 0 20px rgba(249,115,22,0.4), 0 0 40px rgba(249,115,22,0.15)",
    activeBg: "rgba(249,115,22,0.12)",
    icon: "🔥",
  };

  const topDigitColors = ["#14532d", "#1d4ed8", "#0369a1"];
  const topDigitLabels = ["1ST", "2ND", "3RD"];

  const renderCard = (sig: SignalCard) => {
    const inactive = !sig.active;
    return (
      <div
        key={sig.id}
        style={{
          borderRadius: "20px",
          padding: "18px 16px",
          background: inactive ? theme.card : sig.activeBg,
          border: inactive
            ? `1px solid ${theme.border}`
            : `1px solid ${sig.activeColor}55`,
          boxShadow: inactive ? "none" : sig.activeGlow,
          transition: "all 0.4s ease",
          position: "relative",
          overflow: "hidden",
        }}
      >
        {/* Active pulse ring */}
        {sig.active && (
          <div
            style={{
              position: "absolute",
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              borderRadius: "20px",
              border: `2px solid ${sig.activeColor}`,
              animation: "signal-pulse 2s infinite",
              pointerEvents: "none",
            }}
          />
        )}

        {/* Header */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
          <div>
            <div
              style={{
                fontSize: "10px",
                fontWeight: 700,
                letterSpacing: "0.1em",
                color: inactive ? theme.textSub : sig.activeColor,
                marginBottom: "4px",
              }}
            >
              {sig.icon} {sig.sublabel}
            </div>
            <div
              style={{
                fontSize: "18px",
                fontWeight: 800,
                color: inactive ? theme.textMid : sig.activeColor,
                letterSpacing: "0.03em",
              }}
            >
              {sig.label}
            </div>
          </div>

          {/* Status badge */}
          <div
            style={{
              padding: "5px 10px",
              borderRadius: "10px",
              fontSize: "10px",
              fontWeight: 700,
              letterSpacing: "0.08em",
              background: inactive ? "rgba(255,255,255,0.05)" : `${sig.activeColor}25`,
              color: inactive ? theme.textSub : sig.activeColor,
              border: inactive ? "none" : `1px solid ${sig.activeColor}44`,
            }}
          >
            {sig.active ? "● ACTIVE" : "○ WAIT"}
          </div>
        </div>

        {strengthBar(sig.strength)}

        {/* Strength label */}
        <div
          style={{
            marginTop: "8px",
            fontSize: "11px",
            fontWeight: 700,
            color: inactive ? theme.textSub : sig.activeColor,
            letterSpacing: "0.06em",
          }}
        >
          {sig.strength === "INACTIVE" ? "NO SIGNAL" : `⚡ ${sig.strength}`}
        </div>

        {/* Top digits hit count */}
        <div
          style={{
            marginTop: "10px",
            display: "flex",
            gap: "6px",
            alignItems: "center",
          }}
        >
          <span style={{ fontSize: "10px", color: theme.textSub }}>Top digits:</span>
          {top3.map((d, i) => {
            const hit =
              sig.id === "even" ? isEven(d) :
              sig.id === "odd" ? isOdd(d) :
              d < parseInt(sig.id.replace("under", ""));
            return (
              <div
                key={i}
                style={{
                  width: "26px",
                  height: "26px",
                  borderRadius: "8px",
                  background: hit ? topDigitColors[i] : "rgba(255,255,255,0.05)",
                  border: hit ? "none" : `1px solid ${theme.border}`,
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: "12px",
                  fontWeight: 700,
                  color: hit ? "white" : theme.textSub,
                  transition: "all 0.3s",
                }}
              >
                {d}
              </div>
            );
          })}
          <span
            style={{
              fontSize: "10px",
              color: inactive ? theme.textSub : sig.activeColor,
              fontWeight: 600,
              marginLeft: "2px",
            }}
          >
            {sig.matchCount}/3 match
          </span>
        </div>
      </div>
    );
  };

  const activeSignalCount = [...underSignals, evenSignal, oddSignal].filter(
    (s) => s.active
  ).length;

  return (
    <div
      style={{
        background: theme.card,
        borderRadius: "24px",
        padding: "22px",
        border: `1px solid ${theme.border}`,
        boxShadow: theme.shadow,
      }}
    >
      {/* Header */}
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: "18px",
        }}
      >
        <div>
          <h3 style={{ fontSize: "18px", fontWeight: 700, color: theme.text, margin: 0 }}>
            📡 Trading Signals
          </h3>
          <div style={{ fontSize: "11px", color: theme.textSub, marginTop: "3px" }}>
            Based on top 3 most-appearing digits
          </div>
        </div>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: "8px",
            background: activeSignalCount > 0 ? "rgba(34,197,94,0.12)" : theme.cardInner,
            padding: "8px 14px",
            borderRadius: "12px",
            border: activeSignalCount > 0 ? "1px solid rgba(34,197,94,0.3)" : `1px solid ${theme.border}`,
          }}
        >
          <div
            style={{
              width: "8px",
              height: "8px",
              borderRadius: "50%",
              background: activeSignalCount > 0 ? "#22c55e" : theme.textSub,
              animation: activeSignalCount > 0 ? "pulse 1.5s infinite" : "none",
            }}
          />
          <span
            style={{
              fontSize: "13px",
              fontWeight: 700,
              color: activeSignalCount > 0 ? "#22c55e" : theme.textSub,
            }}
          >
            {activeSignalCount} Active
          </span>
        </div>
      </div>

      {/* Top 3 digits legend */}
      <div
        style={{
          display: "flex",
          gap: "8px",
          marginBottom: "16px",
          padding: "10px 14px",
          background: theme.cardInner,
          borderRadius: "12px",
          flexWrap: "wrap",
        }}
      >
        <span style={{ fontSize: "10px", color: theme.textSub, alignSelf: "center", marginRight: "4px" }}>
          Current top 3:
        </span>
        {top3.map((d, i) => (
          <div key={i} style={{ display: "flex", alignItems: "center", gap: "4px" }}>
            <div
              style={{
                width: "30px",
                height: "30px",
                borderRadius: "10px",
                background: topDigitColors[i],
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontSize: "14px",
                fontWeight: 700,
                color: "white",
              }}
            >
              {d}
            </div>
            <div>
              <div style={{ fontSize: "9px", color: theme.textSub, fontWeight: 700 }}>
                {topDigitLabels[i]}
              </div>
              <div style={{ fontSize: "11px", color: theme.text, fontWeight: 600 }}>
                {stats.percentages[d]}%
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Signal grid */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",
          gap: "12px",
        }}
      >
        {underSignals.map(renderCard)}
      </div>

      {/* Even/Odd row */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: "12px",
          marginTop: "12px",
        }}
      >
        {renderCard(evenSignal)}
        {renderCard(oddSignal)}
      </div>

      <style>{`
        @keyframes signal-pulse {
          0%, 100% { opacity: 1; transform: scale(1); }
          50% { opacity: 0.4; transform: scale(1.01); }
        }
      `}</style>
    </div>
  );
}

import { useState } from "react";
import { MARKETS } from "../types";
import type { ActiveView, DigitStats } from "../types";
import { useAllMarketTicks } from "../hooks/useAllMarketTicks";
import { useTheme } from "../contexts/ThemeContext";
import { useHistoricalTicks } from "../hooks/useHistoricalTicks";
import Sidebar from "../components/Sidebar";
import DigitsDistribution from "../components/DigitsDistribution";
import EvenOddAnalysis from "../components/EvenOddAnalysis";
import OverUnderAnalysis from "../components/OverUnderAnalysis";
import FooterPanels from "../components/FooterPanels";
import DigitsHeatmap from "../components/DigitsHeatmap";
import MarketScanner from "../components/MarketScanner";
import KimzAnalysis from "../components/KimzAnalysis";
import SmartSignals from "../components/SmartSignals";
import TradingSignals from "../components/TradingSignals";
import { useMarketScanner } from "../hooks/useMarketScanner";

export function computeStats(
  counts: number[],
  lastDigit: number,
  total: number
): DigitStats {
  if (total === 0) {
    return {
      counts,
      total,
      lastDigit,
      percentages: Array(10).fill("0.0"),
      topDigits: [0, 1, 2],
      bottomDigits: [9, 8, 7],
      evenPercent: 50,
      oddPercent: 50,
      overPercent: 50,
      underPercent: 50,
      signal: "AI Waiting For Signal...",
      matchesProbability: 72,
      differsProbability: 81,
      aiConfidence: 89,
    };
  }

  const percentages = counts.map((c) => ((c / total) * 100).toFixed(1));

  const sorted = counts
    .map((count, index) => ({ count, index }))
    .sort((a, b) => b.count - a.count);

  const topDigits = [sorted[0].index, sorted[1].index, sorted[2].index];
  const bottomDigits = [sorted[9].index, sorted[8].index, sorted[7].index];

  let even = 0;
  let odd = 0;
  counts.forEach((count, index) => {
    if (index % 2 === 0) even += count;
    else odd += count;
  });
  const evenPercent = parseFloat(((even / total) * 100).toFixed(1));
  const oddPercent = parseFloat(((odd / total) * 100).toFixed(1));

  const over = counts.slice(6).reduce((a, b) => a + b, 0);
  const under = counts.slice(0, 6).reduce((a, b) => a + b, 0);
  const overPercent = parseFloat(((over / total) * 100).toFixed(1));
  const underPercent = parseFloat(((under / total) * 100).toFixed(1));

  const signal =
    evenPercent > oddPercent
      ? "AI SIGNAL → EVEN MARKET STRONG"
      : "AI SIGNAL → ODD MARKET STRONG";

  const topPct = parseFloat(percentages[topDigits[0]]);
  const matchesProbability = Math.min(95, Math.max(55, Math.round(topPct * 2.5 + 45)));
  const differsProbability = Math.min(95, Math.max(60, Math.round((100 - topPct) * 0.5 + 65)));
  const aiConfidence = Math.min(97, Math.max(70, Math.round((evenPercent + overPercent) / 2 + 30)));

  return {
    counts,
    total,
    lastDigit,
    percentages,
    topDigits,
    bottomDigits,
    evenPercent,
    oddPercent,
    overPercent,
    underPercent,
    signal,
    matchesProbability,
    differsProbability,
    aiConfidence,
  };
}

export default function Dashboard() {
  const [selectedSymbol, setSelectedSymbol] = useState("R_10");
