     9→function extractLastDigit(quote: number): number {
    10→  return parseInt(quote.toString().slice(-1));
    11→}
    12→
    13→/**
    14→ * Scoring rules per barrier (reversal vs trend logic):
    15→ *
    16→ * Over 7 / Over 8  → REVERSAL: digits ABOVE barrier are underrepresented (due)
    17→ *                    Score = expected%(digits>barrier) − actual%
    18→ *
    19→ * Over 5 / Over 6  → REVERSAL: same (digits above barrier underrepresented)
    20→ *
    21→ * Over 3 / Over 4  → TREND: digits 0,1,2 are the LEAST appearing (most digits >3)
    22→ *                    Score = expected%(0,1,2=30%) − actual%(0,1,2)
    23→ *                    Higher = 0-2 are rarer = trend above 3 is strong
    24→ *
    25→ * Over 1 / Over 2  → REVERSAL (default)
    26→ *
    27→ * Under 5 / Under 6 → TREND: digits 0,1,2,3 are MOST appearing, digits >4 are least
    28→ *                    Score = actual%(0,1,2,3) − expected%(40%)
    29→ *
    30→ * Under 1-4 / Under 7-8 → REVERSAL: digits BELOW barrier underrepresented (due)
    31→ *                    Score = expected%(digits<barrier) − actual%
    32→ */
    33→function scoreOver(barrier: number, counts: number[], total: number): number {
    34→  if (total === 0) return 0;
    35→
    36→  if (barrier === 3 || barrier === 4) {
    37→    // TREND: digits 0,1,2 should be least appearing
    38→    const lowDigits = [0, 1, 2];
    39→    const lowCount = lowDigits.reduce((s, d) => s + counts[d], 0);
    40→    const lowPct = (lowCount / total) * 100;
    41→    const expectedPct = 30; // 3 digits × 10%
    42→    return expectedPct - lowPct; // higher = 0-2 are rarer = upward trend
    43→  }
    44→
    45→  // Default REVERSAL: digits above barrier should be underrepresented (due)
    46→  const targetDigits = Array.from({ length: 10 }, (_, i) => i).filter((d) => d > barrier);
    47→  const targetCount = targetDigits.reduce((s, d) => s + counts[d], 0);
    48→  const targetPct = (targetCount / total) * 100;
    49→  const expectedPct = (targetDigits.length / 10) * 100;
    50→  return expectedPct - targetPct;
    51→}
    52→
    53→function scoreUnder(barrier: number, counts: number[], total: number): number {
    54→  if (total === 0) return 0;
    55→
    56→  if (barrier === 5 || barrier === 6) {
    57→    // TREND: digits 0,1,2,3 are MOST appearing AND digits >4 are least
    58→    const lowDigits = [0, 1, 2, 3];
    59→    const lowCount = lowDigits.reduce((s, d) => s + counts[d], 0);
    60→    const lowPct = (lowCount / total) * 100;
    61→    const expectedPct = 40; // 4 digits × 10%
    62→    return lowPct - expectedPct; // higher = 0-3 appear more than expected = downward trend
    63→  }
    64→
    65→  // Default REVERSAL: digits below barrier should be underrepresented (due)
    66→  const targetDigits = Array.from({ length: 10 }, (_, i) => i).filter((d) => d < barrier);
    67→  const targetCount = targetDigits.reduce((s, d) => s + counts[d], 0);
    68→  const targetPct = (targetCount / total) * 100;
    69→  const expectedPct = (targetDigits.length / 10) * 100;
    70→  return expectedPct - targetPct;
    71→}
