    73→function analyzeMarket(market: Market, counts: number[], total: number): ScanResult {
    74→  const percentages = counts.map((c) => ((c / Math.max(total, 1)) * 100).toFixed(1));
    75→
    76→  const overScore: Record<number, number> = {};
    77→  const underScore: Record<number, number> = {};
    78→
    79→  for (const barrier of [1, 2, 3, 4, 5, 6, 7, 8]) {
    80→    overScore[barrier] = scoreOver(barrier, counts, total);
    81→    underScore[barrier] = scoreUnder(barrier, counts, total);
    82→  }
    83→
    84→  const evenCount = [0, 2, 4, 6, 8].reduce((s, d) => s + counts[d], 0);
    85→  const oddCount = [1, 3, 5, 7, 9].reduce((s, d) => s + counts[d], 0);
    86→  const evenPct = total > 0 ? (evenCount / total) * 100 : 50;
    87→  const oddPct = total > 0 ? (oddCount / total) * 100 : 50;
    88→  const evenScore = 50 - evenPct;
    89→  const oddScore = 50 - oddPct;
    90→
    91→  const godFor: string[] = [];
    92→  if (evenScore > 5) godFor.push("EVEN");
    93→  if (oddScore > 5) godFor.push("ODD");
    94→  for (const [b, score] of Object.entries(overScore)) {
    95→    if (score > 5) godFor.push(`OVER ${b}`);
    96→  }
    97→  for (const [b, score] of Object.entries(underScore)) {
    98→    if (score > 5) godFor.push(`UNDER ${b}`);
    99→  }
   100→
