const UNDER_OVER_THRESHOLD = 90;
const EVEN_ODD_THRESHOLD = 60;

function analyzeMarket(market: Market, counts: number[], total: number): ScanResult {
  const percentages = counts.map((c) => ((c / Math.max(total, 1)) * 100).toFixed(1));

  const overScore: Record<number, number> = {};
  const underScore: Record<number, number> = {};

  for (const barrier of [1, 2, 3, 4, 5, 6, 7, 8]) {
    overScore[barrier] = scoreOver(barrier, counts, total);
    underScore[barrier] = scoreUnder(barrier, counts, total);
  }

  const evenCount = [0, 2, 4, 6, 8].reduce((s, d) => s + counts[d], 0);
  const oddCount = [1, 3, 5, 7, 9].reduce((s, d) => s + counts[d], 0);
  const evenPct = total > 0 ? (evenCount / total) * 100 : 50;
  const oddPct = total > 0 ? (oddCount / total) * 100 : 50;
  const evenScore = 50 - evenPct;
  const oddScore = 50 - oddPct;

  // Actual win-side cumulative percentages for threshold detection
  const sr = (from: number, to: number) =>
    counts.slice(from, to + 1).reduce((a, b) => a + b, 0) / Math.max(total, 1) * 100;

  const winRates: Record<string, number> = {
    under6: sr(0, 5),
    under7: sr(0, 6),
    under8: sr(0, 7),
    under9: sr(0, 8),
    over4:  sr(5, 9),
    over3:  sr(4, 9),
    over2:  sr(3, 9),
    over1:  sr(2, 9),
    even:   evenPct,
    odd:    oddPct,
  };

  // Best signal = highest win-rate that meets its threshold
  const candidates: { trade: string; winRate: number; meetsThreshold: boolean }[] = [
    { trade: "UNDER 6", winRate: winRates.under6, meetsThreshold: winRates.under6 >= UNDER_OVER_THRESHOLD },
    { trade: "UNDER 7", winRate: winRates.under7, meetsThreshold: winRates.under7 >= UNDER_OVER_THRESHOLD },
    { trade: "UNDER 8", winRate: winRates.under8, meetsThreshold: winRates.under8 >= UNDER_OVER_THRESHOLD },
    { trade: "UNDER 9", winRate: winRates.under9, meetsThreshold: winRates.under9 >= UNDER_OVER_THRESHOLD },
    { trade: "OVER 4",  winRate: winRates.over4,  meetsThreshold: winRates.over4  >= UNDER_OVER_THRESHOLD },
    { trade: "OVER 3",  winRate: winRates.over3,  meetsThreshold: winRates.over3  >= UNDER_OVER_THRESHOLD },
    { trade: "OVER 2",  winRate: winRates.over2,  meetsThreshold: winRates.over2  >= UNDER_OVER_THRESHOLD },
    { trade: "OVER 1",  winRate: winRates.over1,  meetsThreshold: winRates.over1  >= UNDER_OVER_THRESHOLD },
    { trade: "EVEN",    winRate: winRates.even,   meetsThreshold: winRates.even   >= EVEN_ODD_THRESHOLD },
    { trade: "ODD",     winRate: winRates.odd,    meetsThreshold: winRates.odd    >= EVEN_ODD_THRESHOLD },
  ];

  const meeting = candidates.filter((c) => c.meetsThreshold);
  const bestSignal = meeting.length > 0
    ? meeting.reduce((best, c) => c.winRate > best.winRate ? c : best)
    : null;

  const godFor: string[] = [];
  if (evenScore > 5) godFor.push("EVEN");
  if (oddScore > 5) godFor.push("ODD");
  for (const [b, score] of Object.entries(overScore)) {
    if (score > 5) godFor.push(`OVER ${b}`);
  }
  for (const [b, score] of Object.entries(underScore)) {
    if (score > 5) godFor.push(`UNDER ${b}`);
  }

  return {
    market,
    counts,
    percentages,
    overScore,
    underScore,
    evenScore,
    oddScore,
    totalTicks: total,
    godFor,
    winRates,
    bestSignal,
  };
}

