import { useState, useRef, useCallback, useEffect } from "react";

const WS_URL = "wss://ws.binaryws.com/websockets/v3?app_id=1089";

export type DerivAccount = {
  loginid: string;
  currency: string;
  balance: number;
  accountType: "demo" | "real";
  email: string;
  fullname: string;
};

export type TradeParams = {
  symbol: string;
  contractType: "DIGITUNDER" | "DIGITOVER" | "DIGITEVEN" | "DIGITODD";
  barrier?: number;
  stake: number;
  duration: number;
  currency: string;
};

export type TradeRecord = {
  id: string;
  contractId?: number;
  symbol: string;
  contractType: string;
  barrier?: number;
  stake: number;
  payout?: number;
  status: "pending" | "open" | "won" | "lost" | "error";
  profit?: number;
  entrySpot?: number;
  exitSpot?: number;
  timestamp: Date;
  error?: string;
};

export type ProposalResult = {
  id: string;
  payout: number;
  stake: number;
  longcode: string;
};

type UseDerivAuthReturn = {
  account: DerivAccount | null;
  isAuthorizing: boolean;
  isAuthorized: boolean;
  error: string | null;
  trades: TradeRecord[];
  authorize: (token: string) => void;
  logout: () => void;
  getProposal: (params: TradeParams) => Promise<ProposalResult>;
  placeTrade: (params: TradeParams, proposalId: string) => Promise<TradeRecord>;
  clearError: () => void;
};

const TOKEN_KEY = "kimz_deriv_token";

export function useDerivAuth(): UseDerivAuthReturn {
  const [account, setAccount] = useState<DerivAccount | null>(null);
  const [isAuthorizing, setIsAuthorizing] = useState(false);
  const [isAuthorized, setIsAuthorized] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [trades, setTrades] = useState<TradeRecord[]>([]);

  const wsRef = useRef<WebSocket | null>(null);
  const pendingRef = useRef<Map<string, { resolve: (v: unknown) => void; reject: (e: Error) => void }>>(new Map());
  const reqIdRef = useRef(1);

  const nextId = () => String(reqIdRef.current++);

  const send = useCallback((payload: Record<string, unknown>): Promise<unknown> => {
    return new Promise((resolve, reject) => {
      const ws = wsRef.current;
      if (!ws || ws.readyState !== WebSocket.OPEN) {
        reject(new Error("WebSocket not connected"));
        return;
      }
      const reqId = nextId();
      const msg = { ...payload, req_id: parseInt(reqId) };
      pendingRef.current.set(reqId, { resolve, reject });
      ws.send(JSON.stringify(msg));
      // Timeout for pending requests
      setTimeout(() => {
        if (pendingRef.current.has(reqId)) {
          pendingRef.current.delete(reqId);
          reject(new Error("Request timed out"));
        }
      }, 15000);
    });
  }, []);

  const connect = useCallback((): Promise<WebSocket> => {
    return new Promise((resolve, reject) => {
      if (wsRef.current?.readyState === WebSocket.OPEN) {
        resolve(wsRef.current);
        return;
      }
      const ws = new WebSocket(WS_URL);
      wsRef.current = ws;
      ws.onopen = () => resolve(ws);
      ws.onerror = () => reject(new Error("Connection failed"));
      ws.onmessage = (evt) => {
        const data = JSON.parse(evt.data);
        const reqId = String(data.req_id);
        const pending = pendingRef.current.get(reqId);
        if (pending) {
          pendingRef.current.delete(reqId);
          if (data.error) {
            pending.reject(new Error(data.error.message));
          } else {
            pending.resolve(data);
          }
        }
        // Handle balance subscriptions
        if (data.msg_type === "balance" && data.balance) {
          setAccount((prev) =>
            prev ? { ...prev, balance: data.balance.balance } : prev
          );
        }
        // Handle open contract updates
        if (data.msg_type === "proposal_open_contract" && data.proposal_open_contract) {
          const poc = data.proposal_open_contract;
          if (poc.is_sold || poc.status === "won" || poc.status === "lost") {
            setTrades((prev) =>
              prev.map((t) =>
                t.contractId === poc.contract_id
                  ? {
                      ...t,
                      status: poc.status === "won" ? "won" : "lost",
                      profit: poc.profit,
                      exitSpot: poc.exit_tick,
                      payout: poc.payout,
                    }
                  : t
              )
            );
          }
        }
      };
      ws.onclose = () => {
        if (isAuthorized) {
          setIsAuthorized(false);
          setAccount(null);
        }
      };
    });
  }, [isAuthorized]);

  const authorize = useCallback(async (token: string) => {
    setIsAuthorizing(true);
    setError(null);
    try {
      await connect();
      const resp = await send({ authorize: token }) as { authorize: { loginid: string; currency: string; balance: number; email: string; fullname: string; account_type: string } };
      const auth = resp.authorize;
      setAccount({
        loginid: auth.loginid,
        currency: auth.currency,
        balance: auth.balance,
        accountType: auth.account_type === "real" ? "real" : "demo",
        email: auth.email,
        fullname: auth.fullname,
      });
      setIsAuthorized(true);
      localStorage.setItem(TOKEN_KEY, token);
      // Subscribe to balance updates
      send({ balance: 1, subscribe: 1 }).catch(() => {});
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Authorization failed";
      setError(msg);
    } finally {
      setIsAuthorizing(false);
    }
  }, [connect, send]);

  const logout = useCallback(() => {
    localStorage.removeItem(TOKEN_KEY);
    if (wsRef.current) {
      wsRef.current.onclose = null;
      wsRef.current.close();
      wsRef.current = null;
    }
    setAccount(null);
    setIsAuthorized(false);
    setError(null);
    pendingRef.current.clear();
  }, []);

  const getProposal = useCallback(async (params: TradeParams): Promise<ProposalResult> => {
    const req: Record<string, unknown> = {
      proposal: 1,
      amount: params.stake,
      basis: "stake",
      contract_type: params.contractType,
      currency: params.currency,
      duration: params.duration,
      duration_unit: "t",
      symbol: params.symbol,
    };
    if (params.barrier !== undefined && (params.contractType === "DIGITUNDER" || params.contractType === "DIGITOVER")) {
      req.barrier = String(params.barrier);
    }
    const resp = await send(req) as { proposal: { id: string; payout: number; ask_price: number; longcode: string } };
    return {
      id: resp.proposal.id,
      payout: resp.proposal.payout,
      stake: resp.proposal.ask_price,
      longcode: resp.proposal.longcode,
    };
  }, [send]);

  const placeTrade = useCallback(async (params: TradeParams, proposalId: string): Promise<TradeRecord> => {
    const record: TradeRecord = {
      id: Date.now().toString(),
      symbol: params.symbol,
      contractType: params.contractType,
      barrier: params.barrier,
      stake: params.stake,
      status: "pending",
      timestamp: new Date(),
    };
    setTrades((prev) => [record, ...prev.slice(0, 49)]);
    try {
      const buyResp = await send({ buy: proposalId, price: params.stake }) as {
        buy: { contract_id: number; payout: number; buy_price: number; shortcode: string };
      };
      const updated: TradeRecord = {
        ...record,
        contractId: buyResp.buy.contract_id,
        payout: buyResp.buy.payout,
        stake: buyResp.buy.buy_price,
        status: "open",
      };
      setTrades((prev) => prev.map((t) => (t.id === record.id ? updated : t)));
      // Subscribe to contract updates
      send({ proposal_open_contract: 1, subscribe: 1, contract_id: buyResp.buy.contract_id }).catch(() => {});
      return updated;
    } catch (err) {
      const errRecord: TradeRecord = {
        ...record,
        status: "error",
        error: err instanceof Error ? err.message : "Trade failed",
      };
      setTrades((prev) => prev.map((t) => (t.id === record.id ? errRecord : t)));
      throw err;
    }
  }, [send]);

  // Auto-connect with saved token on mount
  useEffect(() => {
    const saved = localStorage.getItem(TOKEN_KEY);
    if (saved) authorize(saved);
    return () => {
      if (wsRef.current) {
        wsRef.current.onclose = null;
        wsRef.current.close();
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return {
    account,
    isAuthorizing,
    isAuthorized,
    error,
    trades,
    authorize,
    logout,
    getProposal,
    placeTrade,
    clearError: () => setError(null),
  };
}

import { useState, useCallback } from "react";
import { useTheme } from "../contexts/ThemeContext";
import type { DigitStats } from "../types";
import { useDerivAuth, type TradeParams, type ProposalResult, type TradeRecord } from "../hooks/useDerivAuth";

type Props = {
  stats: DigitStats;
  selectedSymbol: string;
  marketLabel: string;
  onClose: () => void;
};

const CONTRACT_TYPES = [
  { type: "DIGITUNDER" as const, label: "UNDER", color: "#22c55e", icon: "⬇" },
  { type: "DIGITOVER" as const,  label: "OVER",  color: "#ec4899", icon: "⬆" },
  { type: "DIGITEVEN" as const,  label: "EVEN",  color: "#06b6d4", icon: "⚡" },
  { type: "DIGITODD"  as const,  label: "ODD",   color: "#f97316", icon: "🔥" },
];

const BARRIERS = [1, 2, 3, 4, 5, 6, 7, 8];
const DURATIONS = [1, 2, 3, 4, 5];
const STAKES = [0.35, 0.5, 1, 2, 5, 10, 20, 50];

const statusColors: Record<TradeRecord["status"], string> = {
  pending: "#6366f1",
  open:    "#f59e0b",
  won:     "#22c55e",
  lost:    "#ef4444",
  error:   "#9ca3af",
};

export default function TradingPanel({ stats, selectedSymbol, marketLabel, onClose }: Props) {
  const { theme } = useTheme();
  const auth = useDerivAuth();

  const [tokenInput, setTokenInput] = useState("");
  const [contractType, setContractType] = useState<"DIGITUNDER" | "DIGITOVER" | "DIGITEVEN" | "DIGITODD">("DIGITUNDER");
  const [barrier, setBarrier] = useState(6);
  const [stake, setStake] = useState(1);
  const [duration, setDuration] = useState(5);
  const [proposal, setProposal] = useState<ProposalResult | null>(null);
  const [fetchingProposal, setFetchingProposal] = useState(false);
  const [placing, setPlacing] = useState(false);
  const [tradeError, setTradeError] = useState<string | null>(null);
  const [tab, setTab] = useState<"trade" | "log">("trade");

  const isBarrierType = contractType === "DIGITUNDER" || contractType === "DIGITOVER";
  const currency = auth.account?.currency ?? "USD";

  const fetchProposal = useCallback(async () => {
    if (!auth.isAuthorized) return;
    setFetchingProposal(true);
    setProposal(null);
    setTradeError(null);
    try {
      const params: TradeParams = {
        symbol: selectedSymbol,
        contractType,
        barrier: isBarrierType ? barrier : undefined,
        stake,
        duration,
        currency,
      };
      const result = await auth.getProposal(params);
      setProposal(result);
    } catch (err) {
      setTradeError(err instanceof Error ? err.message : "Failed to get quote");
    } finally {
      setFetchingProposal(false);
    }
  }, [auth, selectedSymbol, contractType, barrier, stake, duration, currency, isBarrierType]);

  const executeTrade = useCallback(async () => {
    if (!proposal || !auth.isAuthorized) return;
    setPlacing(true);
    setTradeError(null);
    try {
      await auth.placeTrade(
        { symbol: selectedSymbol, contractType, barrier: isBarrierType ? barrier : undefined, stake, duration, currency },
        proposal.id
      );
      setProposal(null);
      setTab("log");
    } catch (err) {
      setTradeError(err instanceof Error ? err.message : "Trade failed");
    } finally {
      setPlacing(false);
    }
  }, [auth, proposal, selectedSymbol, contractType, barrier, stake, duration, currency, isBarrierType]);

  const suggestedType = (() => {
    const top3 = stats.topDigits;
    if (top3.every((d) => d < 5)) return "DIGITUNDER";
    if (top3.every((d) => d > 4)) return "DIGITOVER";
    if (top3.filter((d) => d % 2 === 0).length >= 2) return "DIGITEVEN";
    if (top3.filter((d) => d % 2 !== 0).length >= 2) return "DIGITODD";
    return null;
  })();

  const card = (content: React.ReactNode) => (
    <div style={{ background: theme.cardInner, borderRadius: "14px", padding: "14px 16px", marginBottom: "12px" }}>
      {content}
    </div>
  );

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 300,
        display: "flex",
        alignItems: "flex-end",
        justifyContent: "flex-end",
      }}
    >
      {/* Backdrop */}
      <div
        onClick={onClose}
        style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,0.5)", backdropFilter: "blur(3px)" }}
      />

      {/* Panel */}
      <div
        style={{
          position: "relative",
          width: "420px",
          height: "100vh",
          background: theme.root,
          borderLeft: `1px solid ${theme.border}`,
          overflowY: "auto",
          boxShadow: "-20px 0 60px rgba(0,0,0,0.6)",
          animation: "slide-from-right 0.3s cubic-bezier(0.32,0.72,0,1)",
        }}
      >
        {/* Header */}
        <div
          style={{
            padding: "20px 20px 14px",
            borderBottom: `1px solid ${theme.border}`,
            position: "sticky",
            top: 0,
            background: theme.root,
            zIndex: 10,
          }}
        >
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div>
              <div style={{ fontSize: "17px", fontWeight: 700, color: theme.text }}>💰 Live Trading</div>
              <div style={{ fontSize: "11px", color: theme.textSub, marginTop: "2px" }}>
                {marketLabel}
              </div>
            </div>
            <button
              onClick={onClose}
              style={{ background: theme.cardInner, border: `1px solid ${theme.border}`, color: theme.textSub, width: "32px", height: "32px", borderRadius: "10px", cursor: "pointer", fontSize: "16px" }}
            >
              ✕
            </button>
          </div>

          {/* Account status bar */}
          {auth.isAuthorized && auth.account && (
            <div
              style={{
                marginTop: "12px",
                padding: "10px 14px",
                background: "rgba(34,197,94,0.1)",
                border: "1px solid rgba(34,197,94,0.25)",
                borderRadius: "12px",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
              }}
            >
              <div>
                <div style={{ fontSize: "11px", color: "#4ade80", fontWeight: 700 }}>
                  ✓ {auth.account.accountType === "demo" ? "DEMO" : "REAL"} ACCOUNT
                </div>
                <div style={{ fontSize: "13px", color: theme.text, fontWeight: 600, marginTop: "2px" }}>
                  {auth.account.loginid}
                </div>
              </div>
              <div style={{ textAlign: "right" }}>
                <div style={{ fontSize: "18px", fontWeight: 800, color: "#22c55e" }}>
                  {auth.account.balance.toFixed(2)} {auth.account.currency}
                </div>
                <button
                  onClick={auth.logout}
                  style={{ fontSize: "10px", color: theme.textSub, background: "none", border: "none", cursor: "pointer", marginTop: "2px" }}
                >
                  Disconnect
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Body */}
        <div style={{ padding: "16px 20px" }}>
          {/* ── Not logged in ─────────────────────────────────────── */}
          {!auth.isAuthorized && (
            <div>
              <div
                style={{
                  padding: "20px",
                  background: "rgba(99,102,241,0.08)",
                  border: "1px solid rgba(99,102,241,0.2)",
                  borderRadius: "16px",
                  marginBottom: "16px",
                  textAlign: "center",
                }}
              >
                <div style={{ fontSize: "32px", marginBottom: "10px" }}>🔑</div>
                <div style={{ fontSize: "15px", fontWeight: 700, color: theme.text, marginBottom: "6px" }}>
                  Connect your Deriv account
                </div>
                <div style={{ fontSize: "12px", color: theme.textSub, lineHeight: 1.6 }}>
                  Paste your Deriv API token below to place live trades directly from this app.
                </div>
              </div>

              <div style={{ marginBottom: "14px" }}>
                <div style={{ fontSize: "12px", fontWeight: 600, color: theme.textMid, marginBottom: "6px" }}>
                  API Token
                </div>
                <input
                  type="password"
                  placeholder="Paste your Deriv API token here..."
                  value={tokenInput}
                  onChange={(e) => setTokenInput(e.target.value)}
                  style={{
                    width: "100%",
                    padding: "11px 14px",
                    background: theme.cardInner,
                    border: `1px solid ${theme.border}`,
                    borderRadius: "12px",
                    color: theme.text,
                    fontSize: "13px",
                    boxSizing: "border-box",
                    outline: "none",
                  }}
                />
              </div>

              {auth.error && (
                <div style={{ padding: "10px 14px", background: "rgba(239,68,68,0.1)", border: "1px solid rgba(239,68,68,0.3)", borderRadius: "10px", fontSize: "12px", color: "#f87171", marginBottom: "12px" }}>
                  ⚠ {auth.error}
                </div>
              )}

              <button
                onClick={() => tokenInput.trim() && auth.authorize(tokenInput.trim())}
                disabled={!tokenInput.trim() || auth.isAuthorizing}
                style={{
                  width: "100%",
                  padding: "13px",
                  background: tokenInput.trim() ? "#6366f1" : theme.cardInner,
                  border: "none",
                  borderRadius: "12px",
                  color: "white",
                  fontSize: "14px",
                  fontWeight: 700,
                  cursor: tokenInput.trim() && !auth.isAuthorizing ? "pointer" : "default",
                  marginBottom: "14px",
                }}
              >
                {auth.isAuthorizing ? "⟳ Connecting..." : "Connect to Deriv"}
              </button>

              <div
                style={{
                  padding: "12px",
                  background: theme.cardInner,
                  borderRadius: "12px",
                  fontSize: "11px",
                  color: theme.textSub,
                  lineHeight: 1.7,
                }}
              >
                <strong style={{ color: theme.textMid }}>How to get your API token:</strong>
                <br />
                1. Log in at{" "}
                <a
                  href="https://app.deriv.com/account/api-token"
                  target="_blank"
                  rel="noopener noreferrer"
                  style={{ color: "#6366f1" }}
                >
                  app.deriv.com/account/api-token
                </a>
                <br />
                2. Create a token with <strong>Read</strong> + <strong>Trade</strong> permissions
                <br />
                3. Copy and paste it above
                <br />
                <span style={{ color: "#f59e0b" }}>⚠ Start with a Demo account to test safely</span>
              </div>
            </div>
          )}

          {/* ── Logged in: Trade tabs ──────────────────────────────── */}
          {auth.isAuthorized && (
            <>
              {/* Tabs */}
              <div style={{ display: "flex", gap: "6px", marginBottom: "16px" }}>
                {(["trade", "log"] as const).map((t) => (
                  <button
                    key={t}
                    onClick={() => setTab(t)}
                    style={{
                      flex: 1,
                      padding: "9px",
                      borderRadius: "10px",
                      border: "none",
                      background: tab === t ? "#6366f1" : theme.cardInner,
                      color: tab === t ? "white" : theme.textSub,
                      cursor: "pointer",
                      fontSize: "12px",
                      fontWeight: 700,
                    }}
                  >
                    {t === "trade" ? "🎯 Place Trade" : `📋 Log (${auth.trades.length})`}
                  </button>
                ))}
              </div>

              {/* ── Trade tab ─────────────────────────────────── */}
              {tab === "trade" && (
                <>
                  {/* Signal suggestion */}
                  {suggestedType && (
                    <div
                      style={{
                        padding: "10px 14px",
                        background: "rgba(99,102,241,0.1)",
                        border: "1px solid rgba(99,102,241,0.25)",
                        borderRadius: "12px",
                        marginBottom: "14px",
                        display: "flex",
                        justifyContent: "space-between",
                        alignItems: "center",
                      }}
                    >
                      <div>
                        <div style={{ fontSize: "10px", color: "#a5b4fc", fontWeight: 700 }}>📡 SIGNAL SUGGESTION</div>
                        <div style={{ fontSize: "13px", color: theme.text, fontWeight: 600, marginTop: "2px" }}>
                          {suggestedType.replace("DIGIT", "")}
                        </div>
                      </div>
                      <button
                        onClick={() => setContractType(suggestedType)}
                        style={{ padding: "5px 12px", background: "#6366f1", border: "none", borderRadius: "8px", color: "white", fontSize: "11px", fontWeight: 700, cursor: "pointer" }}
                      >
                        Use
                      </button>
                    </div>
                  )}

                  {/* Contract type */}
                  {card(
                    <>
                      <div style={{ fontSize: "11px", fontWeight: 700, color: theme.textSub, marginBottom: "10px" }}>CONTRACT TYPE</div>
                      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "6px" }}>
                        {CONTRACT_TYPES.map((ct) => (
                          <button
                            key={ct.type}
                            onClick={() => { setContractType(ct.type); setProposal(null); }}
                            style={{
                              padding: "10px 8px",
                              borderRadius: "10px",
                              border: `2px solid ${contractType === ct.type ? ct.color : "transparent"}`,
                              background: contractType === ct.type ? `${ct.color}18` : theme.card,
                              color: contractType === ct.type ? ct.color : theme.textSub,
                              cursor: "pointer",
                              fontSize: "13px",
                              fontWeight: 700,
                              display: "flex",
                              alignItems: "center",
                              justifyContent: "center",
                              gap: "6px",
                            }}
                          >
                            {ct.icon} {ct.label}
                          </button>
                        ))}
                      </div>
                    </>
                  )}

                  {/* Barrier */}
                  {isBarrierType && card(
                    <>
                      <div style={{ fontSize: "11px", fontWeight: 700, color: theme.textSub, marginBottom: "10px" }}>
                        BARRIER &nbsp;<span style={{ color: theme.textSub, fontWeight: 400 }}>(last digit {contractType === "DIGITUNDER" ? "below" : "above"} {barrier})</span>
                      </div>
                      <div style={{ display: "flex", gap: "6px", flexWrap: "wrap" }}>
                        {BARRIERS.map((b) => (
                          <button
                            key={b}
                            onClick={() => { setBarrier(b); setProposal(null); }}
                            style={{
                              width: "38px",
                              height: "38px",
                              borderRadius: "10px",
                              border: `2px solid ${barrier === b ? "#6366f1" : "transparent"}`,
                              background: barrier === b ? "rgba(99,102,241,0.2)" : theme.card,
                              color: barrier === b ? "#a5b4fc" : theme.textSub,
                              cursor: "pointer",
                              fontSize: "13px",
                              fontWeight: 700,
                            }}
                          >
                            {b}
                          </button>
                        ))}
                      </div>
                    </>
                  )}

                  {/* Stake + Duration */}
                  {card(
                    <>
                      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "14px" }}>
                        <div>
                          <div style={{ fontSize: "11px", fontWeight: 700, color: theme.textSub, marginBottom: "8px" }}>
                            STAKE ({currency})
                          </div>
                          <div style={{ display: "flex", flexWrap: "wrap", gap: "5px" }}>
                            {STAKES.map((s) => (
                              <button
                                key={s}
                                onClick={() => { setStake(s); setProposal(null); }}
                                style={{
                                  padding: "5px 9px",
                                  borderRadius: "8px",
                                  border: `2px solid ${stake === s ? "#22c55e" : "transparent"}`,
                                  background: stake === s ? "rgba(34,197,94,0.15)" : theme.card,
                                  color: stake === s ? "#4ade80" : theme.textSub,
                                  cursor: "pointer",
                                  fontSize: "11px",
                                  fontWeight: 700,
                                }}
                              >
                                {s}
                              </button>
                            ))}
                          </div>
                          <input
                            type="number"
                            min={0.35}
                            step={0.01}
                            value={stake}
                            onChange={(e) => { setStake(parseFloat(e.target.value) || 0.35); setProposal(null); }}
                            style={{
                              marginTop: "6px",
                              width: "100%",
                              padding: "8px 10px",
                              background: theme.card,
                              border: `1px solid ${theme.border}`,
                              borderRadius: "8px",
                              color: theme.text,
                              fontSize: "13px",
                              boxSizing: "border-box",
                            }}
                          />
                        </div>
                        <div>
                          <div style={{ fontSize: "11px", fontWeight: 700, color: theme.textSub, marginBottom: "8px" }}>
                            DURATION (ticks)
                          </div>
                          <div style={{ display: "flex", gap: "5px", flexWrap: "wrap" }}>
                            {DURATIONS.map((d) => (
                              <button
                                key={d}
                                onClick={() => { setDuration(d); setProposal(null); }}
                                style={{
                                  width: "36px",
                                  height: "36px",
                                  borderRadius: "10px",
                                  border: `2px solid ${duration === d ? "#f59e0b" : "transparent"}`,
                                  background: duration === d ? "rgba(245,158,11,0.15)" : theme.card,
                                  color: duration === d ? "#fcd34d" : theme.textSub,
                                  cursor: "pointer",
                                  fontSize: "13px",
                                  fontWeight: 700,
                                }}
                              >
                                {d}
                              </button>
                            ))}
                          </div>
                        </div>
                      </div>
                    </>
                  )}

                  {/* Quote / Place trade */}
                  {!proposal ? (
                    <button
                      onClick={fetchProposal}
                      disabled={fetchingProposal}
                      style={{
                        width: "100%",
                        padding: "14px",
                        background: fetchingProposal ? theme.cardInner : "#6366f1",
                        border: "none",
                        borderRadius: "14px",
                        color: "white",
                        fontSize: "14px",
                        fontWeight: 700,
                        cursor: fetchingProposal ? "default" : "pointer",
                        marginBottom: "10px",
                      }}
                    >
                      {fetchingProposal ? "⟳ Getting quote..." : "📋 Get Quote"}
                    </button>
                  ) : (
                    <div
                      style={{
                        padding: "16px",
                        background: "rgba(34,197,94,0.08)",
                        border: "1px solid rgba(34,197,94,0.25)",
                        borderRadius: "14px",
                        marginBottom: "10px",
                      }}
                    >
                      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "8px" }}>
                        <span style={{ fontSize: "12px", color: theme.textSub }}>Stake</span>
                        <span style={{ fontSize: "14px", fontWeight: 700, color: theme.text }}>{proposal.stake.toFixed(2)} {currency}</span>
                      </div>
                      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "10px" }}>
                        <span style={{ fontSize: "12px", color: theme.textSub }}>Potential payout</span>
                        <span style={{ fontSize: "16px", fontWeight: 800, color: "#22c55e" }}>{proposal.payout.toFixed(2)} {currency}</span>
                      </div>
                      <div style={{ fontSize: "10px", color: theme.textSub, marginBottom: "12px", lineHeight: 1.5 }}>
                        {proposal.longcode}
                      </div>
                      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "8px" }}>
                        <button
                          onClick={() => setProposal(null)}
                          style={{ padding: "11px", background: theme.cardInner, border: `1px solid ${theme.border}`, borderRadius: "10px", color: theme.textSub, cursor: "pointer", fontSize: "13px", fontWeight: 600 }}
                        >
                          Cancel
                        </button>
                        <button
                          onClick={executeTrade}
                          disabled={placing}
