import { createContext, useContext, type ReactNode } from "react";
import { useDerivAuth, type UseDerivAuthReturn } from "../hooks/useDerivAuth";

const DerivAuthContext = createContext<UseDerivAuthReturn | null>(null);

export function DerivAuthProvider({ children }: { children: ReactNode }) {
  const auth = useDerivAuth();
  return <DerivAuthContext.Provider value={auth}>{children}</DerivAuthContext.Provider>;
}

export function useDerivAuthContext(): UseDerivAuthReturn {
  const ctx = useContext(DerivAuthContext);
  if (!ctx) throw new Error("useDerivAuthContext must be used inside DerivAuthProvider");
  return ctx;
}

import { useState, useRef, useCallback, useEffect } from "react";

const WS_URL = "wss://ws.binaryws.com/websockets/v3?app_id=1089";
const ACCOUNTS_KEY = "kimz_deriv_accounts";
const ACTIVE_KEY   = "kimz_deriv_active";

// ── Types ───────────────────────────────────────────────────────────────────
export type ContractType =
  | "DIGITUNDER"
  | "DIGITOVER"
  | "DIGITEVEN"
  | "DIGITODD"
  | "DIGITDIFF"
  | "DIGITMATCH";

export type DerivAccount = {
  loginid: string;
  currency: string;
  balance: number;
  accountType: "demo" | "real";
  email: string;
  fullname: string;
  isVirtual: boolean;
};

export type TradeParams = {
  symbol: string;
  contractType: ContractType;
  barrier?: number;
  stake: number;
  duration: number;
  currency: string;
};

export type TradeRecord = {
  id: string;
  contractId?: number;
  symbol: string;
  contractType: string;
  barrier?: number;
  stake: number;
  payout?: number;
  status: "pending" | "open" | "won" | "lost" | "error";
  profit?: number;
  exitSpot?: string | number;
  timestamp: Date;
  error?: string;
};

export type ProposalResult = {
  id: string;
  payout: number;
  stake: number;
  longcode: string;
};

export type SavedAccount = {
  loginid: string;
  currency: string;
  balance: number;
  isVirtual: boolean;
  accountType: "demo" | "real";
  token: string;
};

export type UseDerivAuthReturn = {
  account: DerivAccount | null;
  accounts: SavedAccount[];
  isAuthorizing: boolean;
  isAuthorized: boolean;
  error: string | null;
  trades: TradeRecord[];
  authorize: (token: string) => Promise<void>;
  addAccount: (token: string) => Promise<void>;
  switchAccount: (loginid: string) => Promise<void>;
  logout: () => void;
  removeAccount: (loginid: string) => void;
  getProposal: (params: TradeParams) => Promise<ProposalResult>;
  placeTrade: (params: TradeParams, proposalId: string) => Promise<TradeRecord>;
  waitForSettle: (contractId: number) => Promise<TradeRecord>;
  clearError: () => void;
};

// ── Load / save accounts ────────────────────────────────────────────────────
function loadAccounts(): SavedAccount[] {
  try { return JSON.parse(localStorage.getItem(ACCOUNTS_KEY) ?? "[]"); } catch { return []; }
}
function saveAccounts(accts: SavedAccount[]) {
  localStorage.setItem(ACCOUNTS_KEY, JSON.stringify(accts));
}

// ── Hook ────────────────────────────────────────────────────────────────────
export function useDerivAuth(): UseDerivAuthReturn {
  const [account,      setAccount]      = useState<DerivAccount | null>(null);
  const [accounts,     setAccounts]     = useState<SavedAccount[]>(loadAccounts);
  const [isAuthorizing,setIsAuthorizing]= useState(false);
  const [isAuthorized, setIsAuthorized] = useState(false);
  const [error,        setError]        = useState<string | null>(null);
  const [trades,       setTrades]       = useState<TradeRecord[]>([]);

  const wsRef              = useRef<WebSocket | null>(null);
  const pendingRef         = useRef<Map<string, { resolve:(v:unknown)=>void; reject:(e:Error)=>void }>>(new Map());
  const settleCallbacksRef = useRef<Map<number, (r:TradeRecord)=>void>>(new Map());
  const reqIdRef           = useRef(1);
  const tradesRef          = useRef<TradeRecord[]>([]);

  // Keep tradesRef in sync so settle callbacks can read the latest record
  const updateTrades = useCallback((updater: (prev: TradeRecord[]) => TradeRecord[]) => {
    setTrades(prev => {
      const next = updater(prev);
      tradesRef.current = next;
      return next;
    });
  }, []);

  const nextId = () => String(reqIdRef.current++);

  // ── WebSocket message handler (uses refs — stable reference) ───────────
  const handleMessage = useCallback((evt: MessageEvent) => {
    let data: Record<string, unknown>;
    try { data = JSON.parse(evt.data as string); } catch { return; }

    // Resolve pending request
    const reqId = String(data.req_id);
    const pending = pendingRef.current.get(reqId);
    if (pending) {
      pendingRef.current.delete(reqId);
      if (data.error) pending.reject(new Error((data.error as {message:string}).message));
      else            pending.resolve(data);
    }

    // Balance subscription
    if (data.msg_type === "balance" && data.balance) {
      const bal = data.balance as {balance:number};
      setAccount(prev => prev ? { ...prev, balance: bal.balance } : prev);
      setAccounts(prev => {
        const next = prev.map(a => a.loginid === account?.loginid ? { ...a, balance: bal.balance } : a);
        saveAccounts(next);
        return next;
      });
    }

    // Contract update
    if (data.msg_type === "proposal_open_contract" && data.proposal_open_contract) {
      const poc = data.proposal_open_contract as {
        contract_id: number;
        is_sold: number;
        profit: number;
        payout: number;
        exit_tick_display_value: string;
      };

      const settled = poc.is_sold;
      const status: TradeRecord["status"] = settled
        ? (poc.profit >= 0 ? "won" : "lost")
        : "open";

      updateTrades(prev =>
        prev.map(t =>
          t.contractId === poc.contract_id
            ? { ...t, status, profit: poc.profit, payout: poc.payout, exitSpot: poc.exit_tick_display_value }
            : t
        )
      );

      if (settled) {
        const cb = settleCallbacksRef.current.get(poc.contract_id);
        if (cb) {
          settleCallbacksRef.current.delete(poc.contract_id);
          // Use a microtask so tradesRef has been updated
          setTimeout(() => {
            const rec = tradesRef.current.find(t => t.contractId === poc.contract_id);
            if (rec) cb(rec);
          }, 0);
        }
      }
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [account?.loginid, updateTrades]);

  // ── connect ─────────────────────────────────────────────────────────────
  const connect = useCallback((): Promise<WebSocket> => {
    return new Promise((resolve, reject) => {
      // Reuse existing open connection
      if (wsRef.current?.readyState === WebSocket.OPEN) {
        resolve(wsRef.current);
        return;
      }
      // Close any lingering connection
      if (wsRef.current) {
        wsRef.current.onmessage = null;
        wsRef.current.onclose   = null;
        wsRef.current.close();
      }
      const ws = new WebSocket(WS_URL);
      wsRef.current = ws;
      ws.onmessage = handleMessage;
      ws.onopen    = () => resolve(ws);
      ws.onerror   = () => reject(new Error("WebSocket connection failed"));
      ws.onclose   = () => {
        setIsAuthorized(false);
        setAccount(null);
      };
    });
  }, [handleMessage]);

  // ── send ─────────────────────────────────────────────────────────────────
  const send = useCallback((payload: Record<string, unknown>): Promise<unknown> => {
    return new Promise((resolve, reject) => {
      const ws = wsRef.current;
      if (!ws || ws.readyState !== WebSocket.OPEN) {
        reject(new Error("Not connected"));
        return;
      }
      const reqId = nextId();
      pendingRef.current.set(reqId, { resolve, reject });
      ws.send(JSON.stringify({ ...payload, req_id: parseInt(reqId) }));
      setTimeout(() => {
        if (pendingRef.current.has(reqId)) {
          pendingRef.current.delete(reqId);
          reject(new Error("Request timed out"));
        }
      }, 20000);
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // ── authorize ────────────────────────────────────────────────────────────
  const doAuthorize = useCallback(async (token: string): Promise<DerivAccount> => {
    await connect();
    const resp = await send({ authorize: token }) as {
      authorize: {
        loginid: string; currency: string; balance: number;
        email: string; fullname: string; is_virtual: number;
        account_type: string;
      };
    };
    const a = resp.authorize;
    const acct: DerivAccount = {
      loginid:     a.loginid,
      currency:    a.currency,
      balance:     a.balance,
      email:       a.email,
      fullname:    a.fullname,
      isVirtual:   a.is_virtual === 1,
      accountType: a.is_virtual === 1 ? "demo" : "real",
    };
    return acct;
  }, [connect, send]);

  const authorize = useCallback(async (token: string) => {
    setIsAuthorizing(true);
    setError(null);
    try {
      const acct = await doAuthorize(token);
      setAccount(acct);
      setIsAuthorized(true);
      localStorage.setItem(ACTIVE_KEY, acct.loginid);

      // Store in saved accounts
      const saved: SavedAccount = {
        loginid:     acct.loginid,
        currency:    acct.currency,
        balance:     acct.balance,
        isVirtual:   acct.isVirtual,
        accountType: acct.accountType,
        token,
      };
      setAccounts(prev => {
        const next = [...prev.filter(a => a.loginid !== saved.loginid), saved];
        saveAccounts(next);
        return next;
      });

      // Subscribe balance
      send({ balance: 1, subscribe: 1 }).catch(() => {});
    } catch (err) {
      setError(err instanceof Error ? err.message : "Authorization failed");
    } finally {
      setIsAuthorizing(false);
    }
  }, [doAuthorize, send]);

  const addAccount = useCallback(async (token: string) => {
    setIsAuthorizing(true);
    setError(null);
    try {
      // Temporarily authorize to validate token and get account info
      await connect();
      const resp = await send({ authorize: token }) as {
        authorize: {
          loginid: string; currency: string; balance: number;
          email: string; fullname: string; is_virtual: number;
        };
      };
      const a = resp.authorize;
      const saved: SavedAccount = {
        loginid:     a.loginid,
        currency:    a.currency,
        balance:     a.balance,
        isVirtual:   a.is_virtual === 1,
        accountType: a.is_virtual === 1 ? "demo" : "real",
        token,
      };
      setAccounts(prev => {
        const next = [...prev.filter(x => x.loginid !== saved.loginid), saved];
        saveAccounts(next);
        return next;
      });

      // Re-authorize with the currently active account token
      const activeLoginid = localStorage.getItem(ACTIVE_KEY);
      const currentAccounts = loadAccounts();
      const activeAcc = currentAccounts.find(x => x.loginid === activeLoginid);
      if (activeAcc) {
        await doAuthorize(activeAcc.token);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to add account");
    } finally {
      setIsAuthorizing(false);
    }
  }, [connect, send, doAuthorize]);

  const switchAccount = useCallback(async (loginid: string) => {
    const all = loadAccounts();
    const acct = all.find(a => a.loginid === loginid);
    if (!acct) { setError("Account not found"); return; }
    setIsAuthorizing(true);
    setError(null);
    // Clear pending balance sub
    pendingRef.current.clear();
    try {
      const newAcct = await doAuthorize(acct.token);
      setAccount(newAcct);
      setIsAuthorized(true);
      localStorage.setItem(ACTIVE_KEY, loginid);
      send({ balance: 1, subscribe: 1 }).catch(() => {});
    } catch (err) {
      setError(err instanceof Error ? err.message : "Switch failed");
    } finally {
      setIsAuthorizing(false);
    }
  }, [doAuthorize, send]);

  const logout = useCallback(() => {
    localStorage.removeItem(ACTIVE_KEY);
    localStorage.removeItem(ACCOUNTS_KEY);
    if (wsRef.current) {
      wsRef.current.onclose = null;
      wsRef.current.close();
      wsRef.current = null;
    }
    setAccount(null);
    setIsAuthorized(false);
    setAccounts([]);
    setError(null);
    pendingRef.current.clear();
  }, []);

  const removeAccount = useCallback((loginid: string) => {
    setAccounts(prev => {
      const next = prev.filter(a => a.loginid !== loginid);
      saveAccounts(next);
      return next;
    });
    if (account?.loginid === loginid) {
      const remaining = loadAccounts().filter(a => a.loginid !== loginid);
      if (remaining.length > 0) {
        switchAccount(remaining[0].loginid);
      } else {
        logout();
      }
    }
  }, [account?.loginid, switchAccount, logout]);

  // ── getProposal ──────────────────────────────────────────────────────────
  const getProposal = useCallback(async (params: TradeParams): Promise<ProposalResult> => {
    const needsBarrier = ["DIGITUNDER", "DIGITOVER", "DIGITDIFF", "DIGITMATCH"].includes(params.contractType);
    const req: Record<string, unknown> = {
      proposal:      1,
      amount:        params.stake,
      basis:         "stake",
      contract_type: params.contractType,
      currency:      params.currency,
      duration:      params.duration,
      duration_unit: "t",
      symbol:        params.symbol,
    };
    if (needsBarrier && params.barrier !== undefined) {
      req.barrier = String(params.barrier);
    }
    const resp = await send(req) as { proposal: { id: string; payout: number; ask_price: number; longcode: string } };
    return {
      id:       resp.proposal.id,
      payout:   resp.proposal.payout,
      stake:    resp.proposal.ask_price,
      longcode: resp.proposal.longcode,
    };
  }, [send]);

  // ── placeTrade ───────────────────────────────────────────────────────────
  const placeTrade = useCallback(async (params: TradeParams, proposalId: string): Promise<TradeRecord> => {
    const record: TradeRecord = {
      id:           Date.now().toString(),
      symbol:       params.symbol,
      contractType: params.contractType,
      barrier:      params.barrier,
      stake:        params.stake,
      status:       "pending",
      timestamp:    new Date(),
    };
    updateTrades(prev => [record, ...prev.slice(0, 99)]);

    try {
      const resp = await send({ buy: proposalId, price: params.stake }) as {
        buy: { contract_id: number; payout: number; buy_price: number };
      };
      const updated: TradeRecord = {
        ...record,
        contractId: resp.buy.contract_id,
        payout:     resp.buy.payout,
        stake:      resp.buy.buy_price,
        status:     "open",
      };
      updateTrades(prev => prev.map(t => t.id === record.id ? updated : t));
      // Subscribe to contract updates
      send({ proposal_open_contract: 1, subscribe: 1, contract_id: resp.buy.contract_id }).catch(() => {});
      return updated;
    } catch (err) {
      const errRecord: TradeRecord = {
        ...record,
        status: "error",
        error: err instanceof Error ? err.message : "Trade failed",
      };
      updateTrades(prev => prev.map(t => t.id === record.id ? errRecord : t));
      throw err;
    }
  }, [send, updateTrades]);

  // ── waitForSettle ────────────────────────────────────────────────────────
  const waitForSettle = useCallback((contractId: number): Promise<TradeRecord> => {
    return new Promise((resolve, reject) => {
      const timeout = setTimeout(() => {
        settleCallbacksRef.current.delete(contractId);
        reject(new Error("Contract settlement timed out"));
      }, 120000); // 2 min timeout

      settleCallbacksRef.current.set(contractId, (record) => {
        clearTimeout(timeout);
        resolve(record);
      });
    });
  }, []);

  // ── Auto-reconnect on mount ──────────────────────────────────────────────
  useEffect(() => {
    const activeLoginid = localStorage.getItem(ACTIVE_KEY);
    const saved = loadAccounts();
    if (saved.length > 0) setAccounts(saved);
    if (activeLoginid) {
      const acct = saved.find(a => a.loginid === activeLoginid) ?? saved[0];
      if (acct) authorize(acct.token);
    }
    return () => {
      if (wsRef.current) {
        wsRef.current.onmessage = null;
        wsRef.current.onclose   = null;
        wsRef.current.close();
      }
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return {
    account, accounts, isAuthorizing, isAuthorized, error, trades,
    authorize, addAccount, switchAccount, logout, removeAccount,
    getProposal, placeTrade, waitForSettle,
    clearError: () => setError(null),
  };
}

